const raw = $input.first().json;
const input = raw.body ?? raw;

const cantidad = Number(input.cantidad || 1);
const plato = String(input.plato || '').toLowerCase().trim();
const id_comanda = input.id_comanda || `CMD-${Date.now()}`;

if (plato === 'ensalada') {
  return [
    {
      json: {
        id_comanda,
        plato: 'Ensalada',
        cantidad,
        ingredientes: [
          { ingrediente: 'Lechuga', consumo: 1 * cantidad },
          { ingrediente: 'Tomate', consumo: 2 * cantidad },
          { ingrediente: 'Atun', consumo: 1 * cantidad }
        ]
      }
    }
  ];
}

if (plato === 'pasta con atun') {
  return [
    {
      json: {
        id_comanda,
        plato: 'Pasta con Atun',
        cantidad,
        ingredientes: [
          { ingrediente: 'Pasta', consumo: 1 * cantidad },
          { ingrediente: 'Atun', consumo: 1 * cantidad }
        ]
      }
    }
  ];
}

throw new Error(`Plato no soportado: ${input.plato}`);

const data = $json;

return data.ingredientes.map(item => ({
  json: {
    id_comanda: data.id_comanda,
    plato: data.plato,
    cantidad: data.cantidad,
    ingrediente: item.ingrediente,
    consumo: item.consumo,
    ventas_30d: data.ventas_30d ?? 0,
    tendencia: data.tendencia ?? 'N/A'
  }
}));

const ingredientesOriginales = $('Code in JavaScript').all().map(item => item.json);

const normalize = value =>
  String(value || '')
    .toLowerCase()
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

return $input.all().map(item => {
  const stock = item.json;

  const ingredienteStock = stock.Ingrediente;

  const ingredienteOriginal = ingredientesOriginales.find(i =>
    normalize(i.ingrediente) === normalize(ingredienteStock)
  );

  const stockActual = Number(stock.Cantidad || 0);
  const consumo = Number(ingredienteOriginal?.consumo || 0);

  const nuevoStock = stockActual - consumo;

  return {
    json: {
      ...stock,
      consumo,
      nuevoStock
    }
  };
});

const normalize = value =>
  String(value || '')
    .toLowerCase()
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const recetaItems = $('Code in JavaScript').all().map(i => i.json);
const stockItems = $('Buscar Inventario').all().map(i => i.json);
const pedidoItems = $('Buscar Pedido').all().map(i => i.json);

const fecha = new Date();
const fecha_actual = fecha.toISOString().split('T')[0];
const mes_actual = fecha.toLocaleString('en-US', { month: 'long' });

const contexto_estacional =
  'In spring and summer, orders for salads and fresh dishes tend to increase. In autumn and winter, hot dishes and soups are more popular.';

return recetaItems.map(receta => {
  const ingrediente = receta.ingrediente;

  const stock = stockItems.find(s =>
    normalize(s.Ingrediente) === normalize(ingrediente)
  );

  const pedido = pedidoItems.find(p =>
    normalize(p.Ingrediente) === normalize(ingrediente)
  );

  const stockActual = Number(stock?.Cantidad ?? 0);
  const pedidoPendiente = Number(pedido?.Cantidad ?? 0);
  const ventas30d = Number(receta.ventas_30d ?? 0);
  const consumoDiario = Number((ventas30d / 30).toFixed(2));

  const diasCobertura =
    consumoDiario > 0 ? Number((stockActual / consumoDiario).toFixed(2)) : 999;

  return {
    json: {
      ingrediente,
      fecha_actual,
      mes_actual,
      stock_actual: stockActual,
      pedido_pendiente: pedidoPendiente,
      buscar_pedido_id: pedido?.id ?? null,
      consumo_30d: ventas30d,
      consumo_diario: consumoDiario,
      dias_cobertura: Math.max(0, diasCobertura),
      ventas_30d: ventas30d,
      tendencia: receta.tendencia || 'stable',
      consumo_actual: Number(receta.consumo ?? 0),
      contexto_estacional
    }
  };
});

const input = $input.first().json;

const text = input.output?.[0]?.content?.[0]?.text;

if (!text) {
  throw new Error('No text found in AI response');
}

const cleaned = text
  .replace(/```json\s*/i, '')
  .replace(/```/g, '')
  .trim();

const data = JSON.parse(cleaned);

if (!Array.isArray(data.pedido)) {
  throw new Error('AI response must contain pedido array');
}

const metadataRaw = $('Preparar datos IA').first().json._metadata || '[]';
const metadata = typeof metadataRaw === 'string'
  ? JSON.parse(metadataRaw)
  : metadataRaw;

const normalize = value =>
  String(value || '')
    .toLowerCase()
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

return data.pedido.map(item => {
  const meta = metadata.find(m =>
    normalize(m.ingrediente) === normalize(item.ingrediente)
  );

  if (!meta?.buscar_pedido_id) {
    throw new Error(`Missing Airtable record ID for ingredient: ${item.ingrediente}`);
  }

  const cantidadAnadir = Number(item.cantidad_a_anadir || 0);
  const pedidoActual = Number(meta.pedido_actual || 0);

  return {
    json: {
      ingrediente: item.ingrediente,
      cantidad_a_anadir: cantidadAnadir,
      buscar_pedido_id: meta.buscar_pedido_id,
      pedido_actual: pedidoActual,
      nueva_cantidad_pedido: pedidoActual + cantidadAnadir
    }
  };
});

const items = $input.all();
const receta = $('DefinirReceta').first().json;

const now = new Date();
const hace30dias = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
const hace60dias = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);

const columnMap = {
  'Ensalada': 'Salad',
  'Pasta con Atun': 'Pasta with tuna'
};
const columna = columnMap[receta.plato] || receta.plato;

let ventas30d = 0;
let ventasPrev30d = 0;
let totalVentas = 0;

for (const item of items) {
  const fecha = item.json.Fecha ? new Date(item.json.Fecha) : null;
  const cantidad = Number(item.json[columna] || 0);
  totalVentas += cantidad;

  if (fecha) {
    if (fecha >= hace30dias) {
      ventas30d += cantidad;
    } else if (fecha >= hace60dias) {
      ventasPrev30d += cantidad;
    }
  }
}

if (ventas30d === 0) ventas30d = totalVentas;

let tendencia = 'N/A';
if (ventasPrev30d > 0) {
  const ratio = ventas30d / ventasPrev30d;
  if (ratio > 1.15) tendencia = 'increasing';
  else if (ratio < 0.85) tendencia = 'decreasing';
  else tendencia = 'stable';
} else if (items.length > 0) {
  tendencia = 'stable';
}

return [{
  json: {
    ...receta,
    ventas_30d: ventas30d,
    tendencia: tendencia
  }
}];

const inputItems = $input.all();
const record = inputItems.length > 0 ? inputItems[0].json : {};
const body = $('Webhook').first().json.body;
const plato = String(body.plato || '').toLowerCase().trim();
const cantidad = Number(body.cantidad || 1);
const today = new Date().toISOString().split('T')[0];

const currentSalad = Number(record.Salad || 0);
const currentPasta = Number(record['Pasta with tuna'] || 0);

const result = {
  Fecha: today,
  Salad: plato === 'ensalada' ? currentSalad + cantidad : currentSalad,
  'Pasta with tuna': plato === 'pasta con atun' ? currentPasta + cantidad : currentPasta
};

if (record.id) {
  result.id = record.id;
}

return [{ json: result }];

const items = $input.all();

const fechaActual = new Date();
const fecha_actual = fechaActual.toISOString().split('T')[0];
const mes_actual = fechaActual.toLocaleString('en-US', { month: 'long' });

const contexto_estacional =
  'In spring and summer, orders for salads and fresh dishes tend to increase. In autumn and winter, hot dishes and soups are more popular.';

const ingredientes = items.map(item => {
  const data = item.json;

  return {
    ingrediente: data.ingrediente,
    stock_actual: Number(data.stock_actual ?? data.Cantidad ?? 0),
    pedido_pendiente: Number(data.pedido_pendiente ?? data.pedido_actual ?? 0),
    consumo_diario: Number(data.consumo_diario ?? 0),
    dias_cobertura: Number(data.dias_cobertura ?? 0),
    ventas_30d: Number(data.ventas_30d ?? data.consumo_30d ?? 0),
    tendencia: data.tendencia || 'stable',
    consumo_actual: Number(data.consumo ?? 0)
  };
});

const metadata = items.map(item => {
  const data = item.json;

  return {
    ingrediente: data.ingrediente,
    buscar_pedido_id: data.buscar_pedido_id,
    pedido_actual: Number(data.pedido_actual ?? data.pedido_pendiente ?? 0)
  };
});

return [
  {
    json: {
      fecha_actual,
      mes_actual,
      contexto_estacional,
      ingredientes: JSON.stringify(ingredientes),
      _metadata: JSON.stringify(metadata)
    }
  }
];
